import { useState } from "react";
import { useDispatch, useSelector } from "react-redux";
import { useNavigate } from "react-router-dom";
import { addAnnonce, setAnnonces } from "../../features/annonces/annoncesSlice";
import { selectAuthUser } from "../../features/auth/authSlice";
import { createAd } from "../../services/api/adsService";
import { uploadImages } from "../../services/api/uploadService";
import { fetchAds } from "../../services/api/adsService";

export default function Publier() {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [selectedImages, setSelectedImages] = useState([]);
  const [error, setError] = useState("");

  const handleImageChange = (e) => {
    const files = Array.from(e.target.files);
    // Limit to 5 images
    if (files.length > 5) {
      setError("Maximum 5 images allowed");
      return;
    }
    setSelectedImages(files);
    setError("");
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");
    setLoading(true);

    try {
      const form = e.target;

      // Validate required fields
      if (!form.titre.value.trim()) {
        setError("Title is required");
        setLoading(false);
        return;
      }

      if (!form.typeAnnonce.value) {
        setError("Type is required");
        setLoading(false);
        return;
      }

      if (!form.prix.value || Number(form.prix.value) <= 0) {
        setError("Valid price is required");
        setLoading(false);
        return;
      }

      if (!form.ville.value.trim()) {
        setError("City is required");
        setLoading(false);
        return;
      }

      // Upload images if any
      let imageUrls = [];
      if (selectedImages.length > 0) {
        try {
          imageUrls = await uploadImages(selectedImages);
        } catch {
          setError("Failed to upload images. Please try again.");
          setLoading(false);
          return;
        }
      }

      // Prepare ad data for PHP API
      const adData = {
        title: form.titre.value.trim(),
        description: form.description.value.trim() || null,
        typeAnnonce: form.typeAnnonce.value,
        category: form.categorie?.value || null,
        subcategory: form.sousCategorie?.value || null,
        price: Number(form.prix.value),
        city: form.ville.value.trim(),
        images: imageUrls,
      };

      // Save to PHP API
      const newAd = await createAd(adData);

      // Update Redux with new ad (transform PHP API format to Redux format)
      const reduxAd = {
        id: newAd.id.toString(),
        titre: newAd.title,
        description: newAd.description,
        typeAnnonce: newAd.type_annonce,
        categorieId: newAd.category,
        sousCategorieId: newAd.subcategory,
        prix: parseFloat(newAd.price),
        ville: newAd.city,
        photos: newAd.images || [],
        userId: newAd.user_id.toString(),
        etat: newAd.status === "pending" ? "en_attente" : newAd.status === "accepted" ? "acceptee" : "refusee",
        datePoster: newAd.created_at,
      };

      dispatch(addAnnonce(reduxAd));

      // Refresh ads list from PHP API
      const allAds = await fetchAds();
      const reduxAds = allAds.map((ad) => ({
        id: ad.id.toString(),
        titre: ad.title,
        description: ad.description,
        typeAnnonce: ad.type_annonce,
        categorieId: ad.category,
        sousCategorieId: ad.subcategory,
        prix: parseFloat(ad.price),
        ville: ad.city,
        photos: ad.images || [],
        userId: ad.user_id.toString(),
        etat: ad.status === "pending" ? "en_attente" : ad.status === "accepted" ? "acceptee" : "refusee",
        datePoster: ad.created_at,
      }));
      dispatch(setAnnonces(reduxAds));

      form.reset();
      setSelectedImages([]);
      alert("Annonce submitted successfully! It's pending admin approval.");
      navigate("/");
    } catch (err) {
      console.error("Error creating ad:", err);
      setError(err.message || "Failed to create ad. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <main className="container" style={{ padding: "60px 0", maxWidth: "700px" }}>
      <div style={{
        background: "var(--card)",
        padding: "40px",
        borderRadius: "14px",
        border: "1px solid var(--border)",
        boxShadow: "0 8px 20px rgba(0, 0, 0, 0.04)"
      }}>
        <h1 style={{ 
          fontSize: "32px", 
          fontWeight: "700", 
          marginBottom: "8px" 
        }}>
          Publish an Announcement
        </h1>
        <p style={{ 
          color: "var(--muted)", 
          marginBottom: "32px",
          fontSize: "15px"
        }}>
          Fill in the details below to create your ad
        </p>

        {error && (
          <div style={{
            background: "#fee2e2",
            color: "#dc2626",
            padding: "12px",
            borderRadius: "8px",
            marginBottom: "20px",
            fontSize: "14px"
          }}>
            {error}
          </div>
        )}

        <form onSubmit={handleSubmit}>
          <div style={{ marginBottom: "20px" }}>
            <label style={{ 
              display: "block", 
              marginBottom: "8px", 
              fontSize: "14px", 
              fontWeight: "500",
              color: "var(--text)"
            }}>
              Title *
            </label>
            <input
              name="titre"
              type="text"
              required
              className="input"
              style={{ width: "100%" }}
              placeholder="e.g., Apartment for rent in Casablanca"
            />
          </div>

          <div style={{ marginBottom: "20px" }}>
            <label style={{ 
              display: "block", 
              marginBottom: "8px", 
              fontSize: "14px", 
              fontWeight: "500",
              color: "var(--text)"
            }}>
              Description
            </label>
            <textarea
              name="description"
              rows="5"
              className="input"
              style={{ width: "100%", resize: "vertical" }}
              placeholder="Describe your item or service in detail..."
            />
          </div>

          <div style={{ marginBottom: "20px" }}>
            <label style={{ 
              display: "block", 
              marginBottom: "8px", 
              fontSize: "14px", 
              fontWeight: "500",
              color: "var(--text)"
            }}>
              Category
            </label>
            <select
              name="categorie"
              className="input"
              style={{ width: "100%" }}
            >
              <option value="">Select category (optional)</option>
              <option value="vehicles">🚗 Vehicles</option>
              <option value="real-estate">🏠 Real Estate</option>
              <option value="electronics">💻 Electronics</option>
              <option value="clothing">👗 Clothing</option>
              <option value="jobs">🧑‍💼 Jobs</option>
            </select>
          </div>

          <div style={{ marginBottom: "20px" }}>
            <label style={{ 
              display: "block", 
              marginBottom: "8px", 
              fontSize: "14px", 
              fontWeight: "500",
              color: "var(--text)"
            }}>
              Type *
            </label>
            <select
              name="typeAnnonce"
              required
              className="input"
              style={{ width: "100%" }}
            >
              <option value="">Select type</option>
              <option value="vente">Sale</option>
              <option value="location">Rental</option>
              <option value="service">Service</option>
            </select>
          </div>

          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "20px", marginBottom: "20px" }}>
            <div>
              <label style={{ 
                display: "block", 
                marginBottom: "8px", 
                fontSize: "14px", 
                fontWeight: "500",
                color: "var(--text)"
              }}>
                Price (MAD) *
              </label>
              <input
                name="prix"
                type="number"
                required
                min="0"
                step="0.01"
                className="input"
                style={{ width: "100%" }}
                placeholder="0"
              />
            </div>

            <div>
              <label style={{ 
                display: "block", 
                marginBottom: "8px", 
                fontSize: "14px", 
                fontWeight: "500",
                color: "var(--text)"
              }}>
                City *
              </label>
              <input
                name="ville"
                type="text"
                required
                className="input"
                style={{ width: "100%" }}
                placeholder="e.g., Casablanca"
              />
            </div>
          </div>

          <div style={{ marginBottom: "24px" }}>
            <label style={{ 
              display: "block", 
              marginBottom: "8px", 
              fontSize: "14px", 
              fontWeight: "500",
              color: "var(--text)"
            }}>
              Images (up to 5)
            </label>
            <input
              type="file"
              accept="image/*"
              multiple
              onChange={handleImageChange}
              className="input"
              style={{ width: "100%", padding: "8px" }}
            />
            {selectedImages.length > 0 && (
              <div style={{ marginTop: "12px", display: "flex", gap: "8px", flexWrap: "wrap" }}>
                {selectedImages.map((file, index) => (
                  <div key={index} style={{
                    position: "relative",
                    width: "80px",
                    height: "80px",
                    borderRadius: "8px",
                    overflow: "hidden",
                    border: "1px solid var(--border)"
                  }}>
                    <img
                      src={URL.createObjectURL(file)}
                      alt={`Preview ${index + 1}`}
                      style={{
                        width: "100%",
                        height: "100%",
                        objectFit: "cover"
                      }}
                    />
                  </div>
                ))}
              </div>
            )}
          </div>

          <button
            type="submit"
            className="btn"
            style={{ width: "100%", marginTop: "8px" }}
            disabled={loading}
          >
            {loading ? "Publishing..." : "Publish Announcement"}
          </button>
        </form>
      </div>
    </main>
  );
}
